#!/usr/bin/env node
/* tools/channel-atlas.js — auto-generated channel registry.

   Walks blocks/ and engines/ adapters, extracts every block's manifest
   (emits / consumes / undoable), aggregates into a global registry, and
   emits a markdown document listing every channel in the system with
   its emitters, consumers, and undoable holders.

   The point: right now if you want to know what `fs.write` expects, you
   grep. The atlas becomes a living doc that's never out of date because
   it's regenerated. Drift between manifest and reality is surfaced.

   Usage:
     node tools/channel-atlas.js                          # write docs/CHANNEL_ATLAS.md
     node tools/channel-atlas.js --stdout                 # print, do not write
     node tools/channel-atlas.js --json                   # JSON dump (machine-readable)
     node tools/channel-atlas.js --check                  # exit 1 if regenerated content
                                                          # differs from on-disk file (CI gate)
*/

'use strict';
const fs   = require('fs');
const path = require('path');
const { inspect } = require('./block-inspect');

const ROOT       = path.resolve(__dirname, '..');
const BLOCKS_DIR = path.join(ROOT, 'blocks');
const OUT_PATH   = path.join(ROOT, 'docs', 'CHANNEL_ATLAS.md');

const argv      = process.argv.slice(2);
const wantJson  = argv.includes('--json');
const wantStdout = argv.includes('--stdout');
const checkMode = argv.includes('--check');

// ── Walk + collect ───────────────────────────────────────────────────────
function findBlocks(dir) {
  const out = [];
  for (const name of fs.readdirSync(dir)) {
    const full = path.join(dir, name);
    const st = fs.statSync(full);
    if (st.isDirectory()) out.push(...findBlocks(full));
    else if (name.endsWith('.html')) out.push(full);
  }
  return out;
}

const blockPaths = findBlocks(BLOCKS_DIR);

// channel -> { emitters: Set, consumers: Set, undoable_in: Set }
const registry = new Map();
function ensure(channel) {
  if (!registry.has(channel)) {
    registry.set(channel, {
      emitters: new Set(),
      consumers: new Set(),
      undoable_in: new Set()
    });
  }
  return registry.get(channel);
}

// also collect block summaries for the per-block index at the bottom
const blockSummaries = [];

for (const p of blockPaths) {
  const rel = path.relative(ROOT, p);
  let report;
  try {
    report = inspect(p);
  } catch (e) {
    console.error(`[atlas] failed to inspect ${rel}: ${e.message}`);
    continue;
  }
  for (const ch of report.manifest.emits)    ensure(ch).emitters.add(rel);
  for (const ch of report.manifest.consumes) ensure(ch).consumers.add(rel);
  for (const ch of report.manifest.undoable) ensure(ch).undoable_in.add(rel);

  blockSummaries.push({
    path: rel,
    classification:
      report.classification.kernel_host  ? 'kernel-host'
    : report.classification.client_backed ? 'client-backed'
    : report.classification.hand_rolled   ? 'hand-rolled'
    : 'unknown',
    emits:    report.manifest.emits.length,
    consumes: report.manifest.consumes.length,
    undoable: report.manifest.undoable.length
  });
}

// ── Renderers ────────────────────────────────────────────────────────────

// Sort channels: ones with at least one emitter and one consumer first
// (the connected graph), then orphans (one side only). Within each group,
// alphabetical.
function sortedChannels() {
  const entries = [...registry.entries()].map(([ch, info]) => ({
    channel: ch,
    emitters: [...info.emitters].sort(),
    consumers: [...info.consumers].sort(),
    undoable_in: [...info.undoable_in].sort(),
    connected: info.emitters.size > 0 && info.consumers.size > 0
  }));
  entries.sort((a, b) => {
    if (a.connected !== b.connected) return a.connected ? -1 : 1;
    return a.channel.localeCompare(b.channel);
  });
  return entries;
}

function renderJson() {
  const obj = {};
  for (const e of sortedChannels()) {
    obj[e.channel] = {
      emitters:    e.emitters,
      consumers:   e.consumers,
      undoable_in: e.undoable_in
    };
  }
  return JSON.stringify({
    generated_at: new Date().toISOString(),
    channel_count: registry.size,
    block_count: blockSummaries.length,
    channels: obj,
    blocks: blockSummaries.sort((a, b) => a.path.localeCompare(b.path))
  }, null, 2);
}

function renderMarkdown() {
  const L = [];
  L.push('# CHANNEL_ATLAS');
  L.push('');
  L.push('**Generated by `tools/channel-atlas.js`. Do not hand-edit.**');
  L.push('');
  L.push('Auto-derived from every block\'s `manifest.emits` / `manifest.consumes` /');
  L.push('`manifest.undoable` declaration. Channels appear once each, with the full set');
  L.push('of blocks that emit, consume, or hold them undoable. Orphans (channels emitted');
  L.push('but never consumed, or vice versa) are listed at the bottom under "Unmatched".');
  L.push('');
  L.push('Static analysis only — channels constructed dynamically (computed strings) are');
  L.push('invisible. Cross-reference with `tests/block-contract-tests.js` Rule C, which');
  L.push('enforces the manifest-vs-emit-call invariant. Cross-reference with');
  L.push('`docs/LANDMINES.md` #3 for the handshake protocol that makes channels work.');
  L.push('');
  L.push(`**Stats:** ${registry.size} channels across ${blockSummaries.length} blocks.`);
  L.push('');
  L.push('---');
  L.push('');

  const entries = sortedChannels();
  const connected = entries.filter(e => e.connected);
  const unmatched = entries.filter(e => !e.connected);

  L.push('## Connected channels');
  L.push('');
  L.push('Channels with at least one emitter and at least one consumer.');
  L.push('');
  for (const e of connected) {
    L.push(`### \`${e.channel}\``);
    L.push('');
    L.push(`- **emitted by:** ${e.emitters.length ? e.emitters.map(p => '`' + p + '`').join(', ') : '_(none)_'}`);
    L.push(`- **consumed by:** ${e.consumers.length ? e.consumers.map(p => '`' + p + '`').join(', ') : '_(none)_'}`);
    if (e.undoable_in.length) {
      L.push(`- **undoable in:** ${e.undoable_in.map(p => '`' + p + '`').join(', ')}`);
    }
    L.push('');
  }

  if (unmatched.length) {
    L.push('---');
    L.push('');
    L.push('## Unmatched');
    L.push('');
    L.push('Channels declared in only one direction. May be intentional (kernel-handled');
    L.push('channels like `nexus.launch`, channels not yet wired up to a consumer, or');
    L.push('channels emitted by external sources). Worth a glance during sweeps.');
    L.push('');
    for (const e of unmatched) {
      L.push(`### \`${e.channel}\``);
      L.push('');
      if (e.emitters.length) L.push(`- **emitted by:** ${e.emitters.map(p => '`' + p + '`').join(', ')}`);
      if (e.consumers.length) L.push(`- **consumed by:** ${e.consumers.map(p => '`' + p + '`').join(', ')}`);
      if (e.undoable_in.length) L.push(`- **undoable in:** ${e.undoable_in.map(p => '`' + p + '`').join(', ')}`);
      L.push('');
    }
  }

  L.push('---');
  L.push('');
  L.push('## Block index');
  L.push('');
  L.push('| Block | Class | emits | consumes | undoable |');
  L.push('|---|---|---|---|---|');
  const sorted = [...blockSummaries].sort((a, b) => a.path.localeCompare(b.path));
  for (const b of sorted) {
    L.push(`| \`${b.path}\` | ${b.classification} | ${b.emits} | ${b.consumes} | ${b.undoable} |`);
  }
  L.push('');
  return L.join('\n');
}

// ── Output ───────────────────────────────────────────────────────────────
const content = wantJson ? renderJson() : renderMarkdown();

if (wantStdout || wantJson) {
  process.stdout.write(content + (content.endsWith('\n') ? '' : '\n'));
  process.exit(0);
}

if (checkMode) {
  if (!fs.existsSync(OUT_PATH)) {
    console.error(`channel-atlas --check: ${path.relative(ROOT, OUT_PATH)} does not exist; run without --check to generate it.`);
    process.exit(1);
  }
  const onDisk = fs.readFileSync(OUT_PATH, 'utf8');
  if (onDisk.trim() !== content.trim()) {
    console.error(`channel-atlas --check: ${path.relative(ROOT, OUT_PATH)} is out of date; run \`node tools/channel-atlas.js\` to regenerate.`);
    process.exit(1);
  }
  console.log(`channel-atlas --check: ${path.relative(ROOT, OUT_PATH)} is up to date.`);
  process.exit(0);
}

fs.writeFileSync(OUT_PATH, content + '\n');
console.log(`channel-atlas: wrote ${path.relative(ROOT, OUT_PATH)} — ${registry.size} channels across ${blockSummaries.length} blocks.`);
